type EventCallback = (data: any) => void;

class DerivService {
  private socket: WebSocket | null = null;
  private listeners: Map<string, EventCallback[]> = new Map();
  private mockInterval: any = null;
  private autoTradeInterval: any = null;
  private balance: number = 0;
  private isTrading: boolean = false;
  private currentStrategy: any = null;
  private lastDigit: number = 0;
  private currentPrice: number = 0;
  private stake: number = 0.35;
  private realAccountBalance: number = 0;
  private realCurrency: string = 'USD';
  private isDemoAccount: boolean = true;

  connect(token: string, isDemo: boolean = true): Promise<void> {
    this.isDemoAccount = isDemo;
    
    console.log(`🔌 Connecting to Deriv ${isDemo ? 'DEMO' : 'REAL'} API...`);
    
    return new Promise((resolve, reject) => {
      try {
        this.socket = new WebSocket('wss://ws.derivws.com/websockets/v3?app_id=1089');
        
        this.socket.onopen = () => {
          console.log('WebSocket open, authorizing...');
          if (token && token !== 'demo') {
            this.socket?.send(JSON.stringify({ authorize: token }));
          } else {
            this.socket?.send(JSON.stringify({ 
              new_account_virtual: 1,
              client_name: 'KXNGTRADER Bot',
              residence: 'us'
            }));
          }
        };

        this.socket.onmessage = (event) => {
          const data = JSON.parse(event.data);
          
          if (data.msg_type === 'authorize') {
            console.log('✅ Authorized! Balance:', data.authorize.balance);
            this.balance = data.authorize.balance;
            this.emit('connected', { 
              balance: this.balance, 
              currency: data.authorize.currency,
              accountType: data.authorize.is_virtual ? 'demo' : 'real'
            });
            resolve();
            this.socket?.send(JSON.stringify({ ticks: 'R_100', subscribe: 1 }));
          }
          
          if (data.msg_type === 'new_account_virtual') {
            console.log('✅ Demo account created! Balance:', data.new_account_virtual.balance);
            this.balance = data.new_account_virtual.balance;
            this.emit('connected', { 
              balance: this.balance,
              currency: 'USD',
              accountType: 'demo'
            });
            resolve();
            this.socket?.send(JSON.stringify({ ticks: 'R_100', subscribe: 1 }));
          }
          
          if (data.msg_type === 'tick') {
            this.currentPrice = data.tick.quote;
            this.lastDigit = Math.floor(this.currentPrice) % 10;
            this.emit('tick', { price: this.currentPrice, digit: this.lastDigit });
          }
          
          if (data.msg_type === 'buy') {
            console.log('✅ Trade placed:', data);
            this.emit('trade_placed', data);
          }
          
          if (data.msg_type === 'proposal_open_contract') {
            if (data.proposal_open_contract.is_sold) {
              const profit = data.proposal_open_contract.profit;
              this.balance += profit;
              this.emit('trade', {
                id: data.proposal_open_contract.contract_id,
                type: data.proposal_open_contract.contract_type,
                stake: data.proposal_open_contract.buy_price,
                profit: profit,
                win: profit > 0,
                timestamp: new Date()
              });
              this.emit('balance', { balance: this.balance });
            }
          }
          
          if (data.msg_type === 'proposal') {
            this.socket?.send(JSON.stringify({ 
              buy: data.proposal.id, 
              price: data.proposal.ask_price 
            }));
          }
          
          if (data.msg_type === 'error') {
            console.error('❌ Error:', data.error);
            this.emit('error', data.error);
          }
        };
        
        this.socket.onerror = (error) => {
          console.error('WebSocket error:', error);
          reject(error);
        };
      } catch (error) {
        console.error('Connection error:', error);
        reject(error);
      }
    });
  }

  createDemoAccount(): Promise<void> {
    return new Promise((resolve, reject) => {
      try {
        console.log('🎮 Creating Deriv Demo Account...');
        this.socket = new WebSocket('wss://ws.derivws.com/websockets/v3?app_id=1089');
        
        this.socket.onopen = () => {
          this.socket?.send(JSON.stringify({ 
            new_account_virtual: 1,
            client_name: 'KXNGTRADER Bot',
            residence: 'us'
          }));
        };

        this.socket.onmessage = (event) => {
          const data = JSON.parse(event.data);
          
          if (data.msg_type === 'new_account_virtual') {
            console.log('✅ Demo account created!');
            this.balance = data.new_account_virtual.balance;
            this.emit('connected', { 
              balance: this.balance,
              currency: 'USD',
              accountType: 'demo'
            });
            resolve();
            this.socket?.send(JSON.stringify({ ticks: 'R_100', subscribe: 1 }));
          }
          
          if (data.msg_type === 'tick') {
            this.currentPrice = data.tick.quote;
            this.lastDigit = Math.floor(this.currentPrice) % 10;
            this.emit('tick', { price: this.currentPrice, digit: this.lastDigit });
          }
          
          if (data.msg_type === 'error') {
            console.error('Error:', data.error);
            reject(data.error);
          }
        };
      } catch (error) {
        reject(error);
      }
    });
  }

  placeTrade(contract: { amount: number; basis: string; contract_type: string; currency: string; duration: number; duration_unit: string; symbol: string; barrier?: string }) {
    console.log('📤 Placing trade:', contract);
    
    const proposalRequest: any = {
      proposal: 1,
      amount: contract.amount,
      basis: contract.basis,
      contract_type: contract.contract_type,
      currency: contract.currency,
      duration: contract.duration,
      duration_unit: contract.duration_unit,
      symbol: contract.symbol
    };
    
    if (contract.barrier) {
      proposalRequest.barrier = contract.barrier;
    }
    
    this.socket?.send(JSON.stringify(proposalRequest));
  }

  startAutoTrading(strategy: any, stakeAmount: number) {
    this.isTrading = true;
    this.currentStrategy = strategy;
    this.stake = stakeAmount;
    
    console.log('🚀 Auto Trading Started');
    
    this.autoTradeInterval = setInterval(() => {
      if (!this.isTrading) return;
      
      const currentDigit = this.lastDigit;
      let contractType = '';
      let barrier: string | undefined = undefined;
      
      const strategyName = strategy?.name || '';
      
      if (strategyName.includes('Prophet') || strategyName.includes('Even')) {
        contractType = currentDigit % 2 === 0 ? 'DIGITODD' : 'DIGITEVEN';
      } else if (strategyName.includes('Ghost') || strategyName.includes('Match')) {
        contractType = 'DIGITDIFF';
        barrier = currentDigit.toString();
      } else if (strategyName.includes('Viper') || strategyName.includes('Over')) {
        contractType = currentDigit > 5 ? 'DIGITUNDER' : 'DIGITOVER';
        barrier = '5';
      } else {
        contractType = currentDigit % 2 === 0 ? 'DIGITODD' : 'DIGITEVEN';
      }
      
      const contract = {
        amount: this.stake,
        basis: 'stake',
        contract_type: contractType,
        currency: 'USD',
        duration: 1,
        duration_unit: 't',
        symbol: 'R_100'
      };
      
      if (barrier) {
        (contract as any).barrier = barrier;
      }
      
      this.placeTrade(contract);
    }, 3000);
  }

  stopAutoTrading() {
    this.isTrading = false;
    if (this.autoTradeInterval) {
      clearInterval(this.autoTradeInterval);
      this.autoTradeInterval = null;
    }
    console.log('🛑 Auto Trading Stopped');
  }

  resetStats() {
    console.log('Stats reset');
    this.emit('stats_reset', {});
  }

  on(event: string, callback: EventCallback) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)?.push(callback);
  }

  private emit(event: string, data: any) {
    this.listeners.get(event)?.forEach(cb => {
      try { cb(data); } catch (e) { console.error(e); }
    });
  }

  disconnect() {
    this.stopAutoTrading();
    if (this.mockInterval) clearInterval(this.mockInterval);
    if (this.autoTradeInterval) clearInterval(this.autoTradeInterval);
    this.socket?.close();
  }
}

export default DerivService;
